<?php
declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('orders.view');$pdo=obtenerConexion();$qtxt=trim((string)($_GET['q']??''));$estado=(string)($_GET['estado']??'');$estados=['pendiente_pago','pagado','preparando','enviado','entregado','cancelado','pago_fallido','reembolsado'];$pagina=max(1,(int)($_GET['pagina']??1));$limite=25;$from=' FROM pedidos p JOIN usuarios u ON u.id=p.usuario_id LEFT JOIN dte_documentos d ON d.pedido_id=p.id';$where=' WHERE 1';$pa=[];if($qtxt!==''){$where.=' AND (p.numero LIKE :q OR u.correo LIKE :q OR p.stripe_checkout_session_id LIKE :q)';$pa['q']='%'.$qtxt.'%';}if(in_array($estado,$estados,true)){$where.=' AND p.estado=:e';$pa['e']=$estado;}$q=$pdo->prepare('SELECT COUNT(*)'.$from.$where);$q->execute($pa);$total=(int)$q->fetchColumn();$sql='SELECT p.*,u.nombre,u.apellido,u.correo,d.estado estado_dte'.$from.$where.' ORDER BY p.created_at DESC LIMIT :lim OFFSET :off';$q=$pdo->prepare($sql);foreach($pa as$k=>$v)$q->bindValue(':'.$k,$v);$q->bindValue(':lim',$limite,PDO::PARAM_INT);$q->bindValue(':off',($pagina-1)*$limite,PDO::PARAM_INT);$q->execute();$pedidos=$q->fetchAll();cmsCabecera('Pedidos','pedidos/index.php','Consulta paginada de pagos, entregas y DTE.');?>
<div class="card card-rounded"><div class="card-body"><form class="row g-2 mb-4"><div class="col-md-6"><input class="form-control" name="q" value="<?=atenea_e($qtxt)?>" placeholder="Pedido, correo o identificador Stripe"></div><div class="col-md-4"><select class="form-select" name="estado"><option value="">Todos los estados</option><?php foreach($estados as$e):?><option value="<?=$e?>" <?=$estado===$e?'selected':''?>><?=atenea_e($e)?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-outline-primary w-100">Filtrar</button></div></form><div class="table-responsive"><table class="table table-hover"><thead><tr><th>Pedido</th><th>Cliente</th><th>Fecha</th><th>Total</th><th>Estado</th><th>DTE</th><th></th></tr></thead><tbody><?php foreach($pedidos as$p):?><tr><td><?=atenea_e($p['numero'])?></td><td><?=atenea_e(trim($p['nombre'].' '.$p['apellido']))?><small class="d-block"><?=atenea_e($p['correo'])?></small></td><td><?=date('d/m/Y H:i',strtotime($p['created_at']))?></td><td>$<?=atenea_e($p['total'])?></td><td><?=atenea_e($p['estado'])?></td><td><?=atenea_e((string)($p['estado_dte']??'—'))?></td><td><a class="btn btn-sm btn-outline-primary" href="detalle.php?id=<?=$p['id']?>">Ver</a></td></tr><?php endforeach;?><?php if(!$pedidos):?><tr><td colspan="7" class="text-center py-5">No hay pedidos.</td></tr><?php endif;?></tbody></table></div><?php $paginas=max(1,(int)ceil($total/$limite));if($paginas>1):?><nav><ul class="pagination justify-content-end"><?php for($i=1;$i<=$paginas;$i++):?><li class="page-item <?=$i===$pagina?'active':''?>"><a class="page-link" href="?pagina=<?=$i?>&q=<?=urlencode($qtxt)?>&estado=<?=urlencode($estado)?>"><?=$i?></a></li><?php endfor;?></ul></nav><?php endif;?></div></div><?php cmsPie();
